// --- Utility Functions ---

function generateSecureToken(bytes = 32) {
  return crypto.randomBytes(bytes).toString('base64url');
}

function hashToken(token) {
  return crypto.createHash('sha256').update(token).digest('hex');
}

function generateCodeChallenge(codeVerifier) {
  return crypto.createHash('sha256').update(codeVerifier).digest('base64url');
}

// --- Authorization Code Storage ---

async function storeAuthorizationCode(code, data) {
  const hashedCode = hashToken(code);
  const ttl = 600; // 10 minutes max per RFC 6749
  await redis.setex(
    `auth_code:${hashedCode}`,
    ttl,
    JSON.stringify({
      ...data,
      created_at: Date.now(),
      used: false,
    })
  );
}

async function consumeAuthorizationCode(code) {
  const hashedCode = hashToken(code);
  const key = `auth_code:${hashedCode}`;
  const data = await redis.get(key);
  if (!data) return null;

  const parsed = JSON.parse(data);
  if (parsed.used) {
    // Code reuse detected - potential attack. Revoke all tokens in this family.
    await revokeTokenFamily(parsed.family_id);
    await redis.del(key);
    return null;
  }

  // Mark as used immediately
  parsed.used = true;
  await redis.setex(key, 60, JSON.stringify(parsed)); // Keep briefly for reuse detection
  return parsed;
}

// --- Token Family Management (for rotation and theft detection) ---

async function createTokenFamily(userId, clientId) {
  const familyId = generateSecureToken(16);
  await redis.setex(
    `token_family:${familyId}`,
    REFRESH_TOKEN_TTL,
    JSON.stringify({
      user_id: userId,
      client_id: clientId,
      created_at: Date.now(),
      revoked: false,
    })
  );
  return familyId;
}

async function revokeTokenFamily(familyId) {
  if (!familyId) return;
  const key = `token_family:${familyId}`;
  const data = await redis.get(key);
  if (data) {
    const parsed = JSON.parse(data);
    parsed.revoked = true;
    await redis.setex(key, 60, JSON.stringify(parsed)); // Brief TTL for cleanup

    // Revoke all refresh tokens in this family
    const familyTokens = await redis.smembers(`token_family_members:${familyId}`);
    const pipeline = redis.pipeline();
    for (const tokenHash of familyTokens) {
      pipeline.del(`refresh_token:${tokenHash}`);
    }
    pipeline.del(`token_family_members:${familyId}`);
    await pipeline.exec();
  }
}

async function isTokenFamilyValid(familyId) {
  const data = await redis.get(`token_family:${familyId}`);
  if (!data) return false;
  const parsed = JSON.parse(data);
  return !parsed.revoked;
}

// --- Refresh Token Storage with Rotation ---

async function storeRefreshToken(token, data) {
  const hashedToken = hashToken(token);
  await redis.setex(
    `refresh_token:${hashedToken}`,
    REFRESH_TOKEN_TTL,
    JSON.stringify({
      ...data,
      created_at: Date.now(),
      rotated: false,
    })
  );
  // Track token in its family
  if (data.family_id) {
    await redis.sadd(`token_family_members:${data.family_id}`, hashedToken);
    await redis.expire(`token_family_members:${data.family_id}`, REFRESH_TOKEN_TTL);
  }
}

async function consumeRefreshToken(token) {
  const hashedToken = hashToken(token);
  const key = `refresh_token:${hashedToken}`;
  const data = await redis.get(key);
  if (!data) return null;

  const parsed = JSON.parse(data);

  // Check if this token was already rotated (reuse detection = potential theft)
  if (parsed.rotated) {
    console.warn(
      `SECURITY: Refresh token reuse detected for family ${parsed.family_id}. ` +
      `Revoking entire token family. Possible token theft.`
    );
    // Revoke the entire token family - this is the key security measure
    await revokeTokenFamily(parsed.family_id);
    return null;
  }

  // Check if the token family is still valid
  if (parsed.family_id && !(await isTokenFamilyValid(parsed.family_id))) {
    await redis.del(key);
    return null;
  }

  // Mark current token as rotated (don't delete yet - keep for reuse detection)
  parsed.rotated = true;
  parsed.rotated_at = Date.now();
  // Keep the old token briefly to detect reuse attempts
  await redis.setex(key, 3600, JSON.stringify(parsed)); // 1 hour for reuse detection

  return parsed;
}

// --- Access Token Storage ---

async function storeAccessToken(token, data) {
  const hashedToken = hashToken(token);
  await redis.setex(
    `access_token:${hashedToken}`,
    ACCESS_TOKEN_TTL,
    JSON.stringify({
      ...data,
      created_at: Date.now(),
    })
  );
}

async function getAccessToken(token) {
  const hashedToken = hashToken(token);
  const data = await redis.get(`access_token:${hashedToken}`);
  return data ? JSON.parse(data) : null;
}

// --- Client Authentication ---

async function authenticateClient(req) {
  let clientId, clientSecret;

  // Check Authorization header (preferred)
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const colonIndex = decoded.indexOf(':');
    if (colonIndex === -1) return null;
    clientId = decodeURIComponent(decoded.slice(0, colonIndex));
    clientSecret = decodeURIComponent(decoded.slice(colonIndex + 1));
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  if (!clientId) return null;

  const client = clients.get(clientId);
  if (!client) return null;

  if (client.client_type === 'confidential') {
    if (!clientSecret || !client.client_secret_hash) return null;
    const valid = await bcrypt.compare(clientSecret, client.client_secret_hash);
    if (!valid) return null;
  }

  return client;
}

// --- PKCE Validation ---

function validatePKCE(codeVerifier, codeChallenge, codeChallengeMethod) {
  if (codeChallengeMethod === 'S256') {
    const computed = generateCodeChallenge(codeVerifier);
    return crypto.timingSafeEqual(
      Buffer.from(computed),
      Buffer.from(codeChallenge)
    );
  }
  // Only support S256 (plain is insecure)
  return false;
}

